  'endgame.bonus.renewable': { de: '-{{pct}}% Kosten erneuerbarer Energie', fr: '-{{pct}}% coût des énergies renouvelables', it: '-{{pct}}% costo energia rinnovabile', ru: '-{{pct}}% к стоимости возобновляемой энергии' },
